// ReactAdapter Functional Handler Conformance Tests
//
// Auto-generated by TestGen from concept spec invariants.
// Validates StorageProgram construction, purity, variant coverage,
// read/write sets, interpreted execution, and invariant conformance.

import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { reactAdapterHandler } from '../../handlers/ts/app/react-adapter.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

const safeInvoke = async (fn: () => any): Promise<any> => {
  let r: any;
  r = (() => { try { return { ok: true, value: fn() }; } catch (e: any) { return { ok: false, message: e?.message }; } })();
  if (!r.ok) return { variant: '_thrown', message: r.message };
  if (r.value?.then) return r.value.catch((e: any) => ({ variant: '_thrown', message: e?.message }));
  return r.value;
};

describe('ReactAdapter functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('normalize', () => {
    it('builds a valid StorageProgram', () => {
      const program = reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('declares completion variants', () => {
      const program = reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = program.effects?.completionVariants ?? extractCompletionVariants(program);
      expect(variants.size).toBeGreaterThan(0);
    });

    it('declares read and write sets', () => {
      const program = reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('produces a result', async () => {
      if (typeof reactAdapterHandler.normalize !== 'function') return;
      const result = await interpret(reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" }), storage);
      expect(result).toBeDefined();
      if (result.variant !== undefined) {
        expect(typeof result.variant).toBe('string');
      }
    });

    it('fixture "event_and_class" -> ok', async () => {
      if (typeof reactAdapterHandler.normalize !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(reactAdapterHandler.normalize({ adapter: "react-1", props: "{\"onclick\":\"handleClick\",\"class\":\"btn primary\",\"for\":\"input-name\"}" }), storage);
      expect(result.variant).toBe('ok');
    });

    it('fixture "with_layout" -> ok', async () => {
      if (typeof reactAdapterHandler.normalize !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(reactAdapterHandler.normalize({ adapter: "react-2", props: "{\"layout\":\"{\\\"kind\\\":\\\"center\\\",\\\"gap\\\":\\\"16px\\\"}\",\"aria-label\":\"main content\"}" }), storage);
      expect(result.variant).toBe('ok');
    });

    it('fixture "empty_props" -> error', async () => {
      if (typeof reactAdapterHandler.normalize !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(reactAdapterHandler.normalize({ adapter: "react-3", props: "" }), storage);
      expect(result.variant).not.toBe('ok');
    });

    it('fixture "invalid_json_props" -> error', async () => {
      if (typeof reactAdapterHandler.normalize !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(reactAdapterHandler.normalize({ adapter: "react-4", props: "{broken" }), storage);
      expect(result.variant).not.toBe('ok');
    });

  });

  describe('register()', () => {
    it('declares concept name', async () => {
      if (typeof reactAdapterHandler.register !== 'function') return;
      const storage = createInMemoryStorage();
      const program = reactAdapterHandler.register({});
      // If it's a StorageProgram, interpret it
      const result = (program?.instructions && !program.variant)
        ? await interpret(program, storage)
        : program;
      if (!result?.variant) return; // handler does not support register introspection
      expect(result.variant).toBe('ok');
      const name = result.output?.name ?? result.name;
      expect(name).toBe('ReactAdapter');
    });
  });

  describe('invariant examples', () => {
    it("normalize succeeds with valid props and fails with empty", async () => {
      const storage = createInMemoryStorage();
      const normalizeResult0 = await interpret(reactAdapterHandler.normalize({ adapter: "test-a", props: "{ \"onclick\": \"handler_1\", \"class\": \"btn\" }" }), storage);
      expect(normalizeResult0.variant).toBe("ok");
      let adapter = normalizeResult0.output["adapter"];
      let a = adapter;
      let normalized = normalizeResult0.output["normalized"];
      let _ = normalized;
      const thenResult0 = await interpret(reactAdapterHandler.normalize({ adapter: a, props: "" }), storage);
      expect(thenResult0.variant).toBe("error");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: normalized output uses React prop conventions', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('normalize'), input: fc.record({ adapter: fc.string(), props: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = reactAdapterHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(reactAdapterHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: normalize produces output with "class" attribute', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('normalize'), input: fc.record({ adapter: fc.string(), props: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = reactAdapterHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(reactAdapterHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: normalize produces output with "class" attribute
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

});
